import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { NavbarComponent } from '../../core/components/navbar/navbar.component';
import { FooterComponent } from '../../core/components/footer/footer.component';

interface Curso {
  slug: string;
  title: string;
  category: 'CORTOS' | 'DIPLOMADOS';
  icon: string;
  rating: number;
  duration: string;
  description: string;
  students: string;
  price: string;
}

@Component({
  selector: 'app-cursos',
  standalone: true,
  imports: [CommonModule, RouterLink, NavbarComponent, FooterComponent],
  templateUrl: './cursos.component.html',
  styleUrls: []
})
export class PublicCursosComponent {
  filter: 'TODOS' | 'CORTOS' | 'DIPLOMADOS' = 'TODOS';

  cursos: Curso[] = [
    {
      slug: 'fundamentos-reiki',
      title: 'Fundamentos de Reiki',
      category: 'CORTOS',
      icon: 'auto_stories',
      rating: 4.9,
      duration: '15 horas',
      description: 'Domina las bases de la sanación energética desde tu hogar para aplicar en el día a día.',
      students: '+1,200',
      price: 'S/ 180'
    },
    {
      slug: 'acupresion-practica',
      title: 'Acupresión Práctica',
      category: 'CORTOS',
      icon: 'vital_signs',
      rating: 4.8,
      duration: '12 horas',
      description: 'Aprende técnicas rápidas de alivio del dolor y estrés usando puntos de presión.',
      students: '+850',
      price: 'S/ 220'
    },
    {
      slug: 'aromaterapia-esencial',
      title: 'Aromaterapia Esencial',
      category: 'CORTOS',
      icon: 'local_florist',
      rating: 4.9,
      duration: '10 horas',
      description: 'Descubre el uso de aceites esenciales para equilibrar la mente, el cuerpo y las emociones.',
      students: '+950',
      price: 'S/ 150'
    },
    {
      slug: 'terapia-integral',
      title: 'Diplomado en Terapia Integral',
      category: 'DIPLOMADOS',
      icon: 'self_improvement',
      rating: 5.0,
      duration: '150 horas',
      description: 'Una formación exhaustiva que combina múltiples disciplinas holísticas para formar terapeutas profesionales.',
      students: '+3,500',
      price: 'S/ 1,850'
    },
    {
      slug: 'herbolaria',
      title: 'Especialización en Herbolaria',
      category: 'DIPLOMADOS',
      icon: 'spa',
      rating: 4.8,
      duration: '120 horas',
      description: 'Profundiza en la medicina natural y plantas curativas con expertos del sector.',
      students: '+1,100',
      price: 'S/ 1,490'
    }
  ];

  setFilter(f: 'TODOS' | 'CORTOS' | 'DIPLOMADOS') {
    this.filter = f;
  }

  filteredCursos() {
    if (this.filter === 'TODOS') return this.cursos;
    return this.cursos.filter(c => c.category === this.filter);
  }
}
<app-navbar></app-navbar>
<main class="pt-20">
  <section class="bg-surface py-20 min-h-screen">
    <div class="max-w-container-max mx-auto px-margin-mobile md:px-margin-desktop">
      <div class="text-center mb-16 space-y-3">
        <span class="inline-block bg-primary/10 text-primary px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider">Catálogo Completo</span>
        <h2 class="font-headline-lg text-headline-lg-mobile md:text-headline-lg text-primary tracking-tight">Nuestros Cursos y Programas</h2>
        <p class="font-body-lg text-on-surface-variant text-base max-w-2xl mx-auto">Explora nuestra oferta educativa especializada en terapias holísticas y alternativas.</p>
      </div>

      <!-- Filters -->
      <div class="flex justify-center gap-4 mb-12">
        <button (click)="setFilter('TODOS')" class="px-6 py-2 rounded-full text-sm font-bold transition-all duration-300" [ngClass]="filter === 'TODOS' ? 'bg-primary text-on-primary shadow-md' : 'bg-surface-container border border-surface-variant text-on-surface-variant hover:bg-surface-variant/30'">Todos</button>
        <button (click)="setFilter('CORTOS')" class="px-6 py-2 rounded-full text-sm font-bold transition-all duration-300" [ngClass]="filter === 'CORTOS' ? 'bg-primary text-on-primary shadow-md' : 'bg-surface-container border border-surface-variant text-on-surface-variant hover:bg-surface-variant/30'">Cursos Cortos</button>
        <button (click)="setFilter('DIPLOMADOS')" class="px-6 py-2 rounded-full text-sm font-bold transition-all duration-300" [ngClass]="filter === 'DIPLOMADOS' ? 'bg-primary text-on-primary shadow-md' : 'bg-surface-container border border-surface-variant text-on-surface-variant hover:bg-surface-variant/30'">Diplomados</button>
      </div>

      <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        <div *ngFor="let curso of filteredCursos()" class="bg-surface-container-lowest rounded-2xl p-8 border border-surface-variant/40 hover:-translate-y-2 hover:shadow-2xl hover:shadow-primary/5 transition-all duration-300 flex flex-col h-full group">
          <div class="flex justify-between items-start mb-6">
            <div class="w-14 h-14 bg-primary/5 rounded-2xl flex items-center justify-center group-hover:bg-primary group-hover:text-white transition-all duration-300">
              <span class="material-symbols-outlined text-3xl text-primary group-hover:text-white">{{ curso.icon }}</span>
            </div>
            <div class="flex flex-col items-end gap-2">
              <div class="flex items-center gap-1 bg-surface-variant px-2 py-1 rounded text-xs font-bold text-on-surface">
                <span class="material-symbols-outlined text-[14px] text-amber-500 fill">star</span> {{ curso.rating }}
              </div>
              <span class="text-xs font-medium text-secondary bg-secondary/10 px-2 py-0.5 rounded font-bold">{{ curso.duration }}</span>
            </div>
          </div>
          <h3 class="font-headline-md text-xl text-primary mb-2 font-bold">{{ curso.title }}</h3>
          <p class="font-body-md text-sm text-on-surface-variant leading-relaxed mb-6 flex-1">{{ curso.description }}</p>
          <div class="pt-6 border-t border-surface-variant/40 mt-auto flex items-center justify-between">
            <div>
              <span class="font-caption text-on-surface-variant flex items-center gap-1 mb-1"><span class="material-symbols-outlined text-sm">group</span> {{ curso.students }} alumnos</span>
              <span class="font-bold text-lg text-primary">{{ curso.price }}</span>
            </div>
            <a [routerLink]="['/cursos', curso.slug]" class="bg-primary text-on-primary font-label-md px-6 py-2.5 rounded-lg shadow-md hover:bg-primary/95 transition-all duration-300 flex items-center gap-1">
              Ver Detalle <span class="material-symbols-outlined text-sm">arrow_forward</span>
            </a>
          </div>
        </div>
      </div>
    </div>
  </section>
</main>
<app-footer></app-footer>
